// Prezik horizontal logo (app/src/assets/prezik-logo-horizontal.png) inlined as a
// base64 data URI. The recorder container only copies recorder/src, so embedding
// it here keeps the outro end card self-contained — no asset file to ship, no
// runtime file lookup that could fail. Regenerate with:
//   base64 -i app/src/assets/prezik-logo-horizontal.png
export const PREZIK_LOGO_DATA_URI =
  "data:image/png;base64,";
